package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Constructor;

class CSVFormatTest {

    @Test
    void testFormatWithNormalValues() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT;
        String result = format.format("a", "b", "c");
        // The output should be CSV record with comma delimiter and CRLF line ending trimmed
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormatWithNullValue() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        String result = format.format("a", null, "c");
        assertEquals("a,NULL,c", result);
    }

    @Test
    void testFormatWithEmptyValues() {
        CSVFormat format = CSVFormat.DEFAULT;
        String result = format.format();
        // Empty record should produce empty string after trim
        assertEquals("", result);
    }

    @Test
    void testFormatWithIOException() throws Exception {
        CSVFormat format = Mockito.spy(CSVFormat.DEFAULT);

        Constructor<CSVPrinter> constructor = CSVPrinter.class.getConstructor(Appendable.class, CSVFormat.class);

        // Use Mockito to mock the constructor call via a wrapper to simulate IOException
        CSVPrinter csvPrinterMock = Mockito.mock(CSVPrinter.class);
        Mockito.doThrow(new IOException("forced IO exception")).when(csvPrinterMock).printRecord(Mockito.any());

        // Replace CSVPrinter constructor usage by spying CSVFormat.format() method to throw IOException
        // Since constructor mocking is very complex, we instead use a subclass of CSVFormat to override format method

        CSVFormat formatWithException = new CSVFormatWithException();

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> formatWithException.format("a"));
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("forced IO exception", thrown.getCause().getMessage());
    }

    private static class CSVFormatWithException extends CSVFormat {
        CSVFormatWithException() {
            super(',', '"', null, null, null, false, true, "\r\n",
                    null, null, null, false, false, false, false, false, false);
        }

        @Override
        public String format(final Object... values) {
            final StringWriter out = new StringWriter();
            try (final CSVPrinter csvPrinter = new CSVPrinter(out, this)) {
                // Simulate IOException when printRecord is called
                throw new IOException("forced IO exception");
            } catch (final IOException e) {
                throw new IllegalStateException(e);
            }
        }
    }

    @Test
    void testFormatWithDifferentFormats() {
        CSVFormat[] formats = new CSVFormat[]{
                CSVFormat.EXCEL,
                CSVFormat.INFORMIX_UNLOAD,
                CSVFormat.INFORMIX_UNLOAD_CSV,
                CSVFormat.MYSQL,
                CSVFormat.POSTGRESQL_CSV,
                CSVFormat.POSTGRESQL_TEXT,
                CSVFormat.RFC4180,
                CSVFormat.TDF
        };

        for (CSVFormat format : formats) {
            String result = format.format("x", "y", "z");
            assertNotNull(result);
            assertFalse(result.isEmpty());
            // Basic check that output contains the first value
            assertTrue(result.contains("x"));
        }
    }
}
